SELECT COUNT(DISTINCT al.user_id) AS unique_users
FROM access_logs al
JOIN dataset_demographics dd ON al.dataset_id = dd.dataset_id;

SELECT dataset_name 
FROM datasets 
WHERE dataset_id IN (
  SELECT dataset_id 
  FROM access_logs 
  WHERE user_id IN (
    SELECT user_id 
    FROM team_members
  )
);
